  1→//! .spc file parser for the pl24r linker.
  2→//!
  3→//! Parses symbolic p-code assembler text files into a structured AST,
  4→//! including the new module metadata directives for linking.
  5→
  6→/// A parsed .spc module.
  7→#[derive(Debug, Clone, PartialEq)]
  8→pub struct Module {
  9→    /// Module name (from `.module` directive or inferred from filename).
 10→    pub name: String,
 11→    /// Symbols explicitly exported via `.export`.
 12→    pub exports: Vec<String>,
 13→    /// Symbols declared as external dependencies via `.extern`.
 14→    pub externs: Vec<String>,
 15→    /// Whether this module had explicit `.module`/`.endmodule` metadata.
 16→    pub has_metadata: bool,
 17→    /// The items (procs, globals, data, constants, comments) in order.
 18→    pub items: Vec<Item>,
 19→}
 20→
 21→/// A top-level item in a .spc file.
 22→#[derive(Debug, Clone, PartialEq)]
 23→pub enum Item {
 24→    Proc(Proc),
 25→    Global(Global),
 26→    Data(Data),
 27→    Const(Const),
 28→    Comment(String),
 29→}
 30→
 31→/// A procedure definition (`.proc NAME nlocals` ... `.end`).
 32→#[derive(Debug, Clone, PartialEq)]
 33→pub struct Proc {
 34→    pub name: String,
 35→    pub nlocals: u32,
 36→    pub body: Vec<Statement>,
 37→}
 38→
 39→/// A statement inside a procedure body.
 40→#[derive(Debug, Clone, PartialEq)]
 41→pub enum Statement {
 42→    Label(String),
 43→    Instruction(Instruction),
 44→    Comment(String),
 45→    Blank,
 46→}
 47→
 48→/// A single p-code instruction with optional operand.
 49→#[derive(Debug, Clone, PartialEq)]
 50→pub struct Instruction {
 51→    pub mnemonic: String,
 52→    pub operand: Option<String>,
 53→    pub comment: Option<String>,
 54→}
 55→
 56→/// A global variable declaration (`.global NAME nwords`).
 57→#[derive(Debug, Clone, PartialEq)]
 58→pub struct Global {
 59→    pub name: String,
 60→    pub nwords: u32,
 61→}
 62→
 63→/// A data declaration (`.data NAME byte,byte,...`).
 64→#[derive(Debug, Clone, PartialEq)]
 65→pub struct Data {
 66→    pub name: String,
 67→    pub bytes: Vec<u8>,
 68→}
 69→
 70→/// A constant declaration (`.const NAME value`).
 71→#[derive(Debug, Clone, PartialEq)]
 72→pub struct Const {
 73→    pub name: String,
 74→    pub value: String,
 75→}
 76→
 77→/// Parse error with line number and description.
 78→#[derive(Debug, Clone, PartialEq)]
 79→pub struct ParseError {
 80→    pub line: usize,
 81→    pub message: String,
 82→}
 83→
 84→impl std::fmt::Display for ParseError {
 85→    fn fmt(&self, f: &mut std::fmt::Formatter<'_>) -> std::fmt::Result {
 86→        write!(f, "line {}: {}", self.line, self.message)
 87→    }
 88→}
 89→
 90→impl std::error::Error for ParseError {}
 91→
 92→/// Parse a .spc file's text content into a `Module`.
 93→///
 94→/// `filename` is used to infer the module name when no `.module` directive is present.
 95→pub fn parse(source: &str, filename: &str) -> Result<Module, ParseError> {
 96→    let mut parser = Parser::new(source, filename);
 97→    parser.parse()
 98→}
 99→
100→struct Parser<'a> {
101→    lines: Vec<&'a str>,
102→    pos: usize,
103→    filename: &'a str,
104→}
105→
106→impl<'a> Parser<'a> {
107→    fn new(source: &'a str, filename: &'a str) -> Self {
108→        Self {
109→            lines: source.lines().collect(),
110→            pos: 0,
111→            filename,
112→        }
113→    }
114→
115→    fn parse(&mut self) -> Result<Module, ParseError> {
116→        let mut module_name: Option<String> = None;
117→        let mut exports = Vec::new();
118→        let mut externs = Vec::new();
119→        let mut items = Vec::new();
120→        let mut has_metadata = false;
121→        let mut in_module = false;
122→
123→        while self.pos < self.lines.len() {
124→            let line_num = self.pos + 1;
125→            let line = self.lines[self.pos];
126→            let trimmed = line.trim();
127→
128→            if trimmed.is_empty() {
129→                self.pos += 1;
130→                continue;
131→            }
132→
133→            if trimmed.starts_with(';') {
134→                items.push(Item::Comment(trimmed.to_string()));
135→                self.pos += 1;
136→                continue;
137→            }
138→
139→            if let Some(directive) = trimmed.strip_prefix('.') {
140→                let parts: Vec<&str> = directive.splitn(2, char::is_whitespace).collect();
141→                let dir_name = parts[0];
142→                let dir_arg = parts.get(1).map(|s| s.trim());
143→
144→                match dir_name {
145→                    "module" => {
146→                        let name = dir_arg.ok_or_else(|| ParseError {
147→                            line: line_num,
148→                            message: ".module requires a name".to_string(),
149→                        })?;
150→                        // Strip inline comment from module name
151→                        let name = name.split(';').next().unwrap().trim();
152→                        module_name = Some(name.to_string());
153→                        has_metadata = true;
154→                        in_module = true;
155→                        self.pos += 1;
156→                    }
157→                    "endmodule" => {
158→                        if !in_module {
159→                            return Err(ParseError {
160→                                line: line_num,
161→                                message: ".endmodule without matching .module".to_string(),
162→                            });
163→                        }
164→                        in_module = false;
165→                        self.pos += 1;
166→                    }
167→                    "export" => {
168→                        let sym = dir_arg.ok_or_else(|| ParseError {
169→                            line: line_num,
170→                            message: ".export requires a symbol name".to_string(),
171→                        })?;
172→                        let sym = sym.split(';').next().unwrap().trim();
173→                        exports.push(sym.to_string());
174→                        self.pos += 1;
175→                    }
176→                    "extern" => {
177→                        let sym = dir_arg.ok_or_else(|| ParseError {
178→                            line: line_num,
179→                            message: ".extern requires a symbol name".to_string(),
180→                        })?;
181→                        let sym = sym.split(';').next().unwrap().trim();
182→                        externs.push(sym.to_string());
183→                        self.pos += 1;
184→                    }
185→                    "proc" => {
186→                        items.push(Item::Proc(self.parse_proc()?));
187→                    }
188→                    "global" => {
189→                        items.push(Item::Global(self.parse_global()?));
190→                        self.pos += 1;
191→                    }
192→                    "data" => {
193→                        items.push(Item::Data(self.parse_data()?));
194→                        self.pos += 1;
195→                    }
196→                    "const" => {
197→                        items.push(Item::Const(self.parse_const()?));
198→                        self.pos += 1;
199→                    }
200→                    _ => {
201→                        return Err(ParseError {
202→                            line: line_num,
203→                            message: format!("unknown directive: .{dir_name}"),
204→                        });
205→                    }
206→                }
207→            } else {
208→                return Err(ParseError {
209→                    line: line_num,
210→                    message: format!("unexpected line: {trimmed}"),
211→                });
212→            }
213→        }
214→
215→        if in_module {
216→            return Err(ParseError {
217→                line: self.lines.len(),
218→                message: ".module without matching .endmodule".to_string(),
219→            });
220→        }
221→
222→        let name = module_name.unwrap_or_else(|| module_name_from_filename(self.filename));
223→
224→        Ok(Module {
225→            name,
226→            exports,
227→            externs,
228→            has_metadata,
229→            items,
230→        })
231→    }
232→
233→    fn parse_proc(&mut self) -> Result<Proc, ParseError> {
234→        let line_num = self.pos + 1;
235→        let line = self.lines[self.pos].trim();
236→
237→        // .proc NAME nlocals
238→        let rest = line.strip_prefix(".proc").unwrap().trim();
239→        // Strip inline comment
240→        let rest = rest.split(';').next().unwrap().trim();
241→        let parts: Vec<&str> = rest.split_whitespace().collect();
242→
243→        if parts.len() < 2 {
244→            return Err(ParseError {
245→                line: line_num,
246→                message: ".proc requires NAME and nlocals".to_string(),
247→            });
248→        }
249→
250→        let name = parts[0].to_string();
251→        let nlocals: u32 = parts[1].parse().map_err(|_| ParseError {
252→            line: line_num,
253→            message: format!("invalid nlocals: {}", parts[1]),
254→        })?;
255→
256→        self.pos += 1;
257→        let mut body = Vec::new();
258→
259→        while self.pos < self.lines.len() {
260→            let bline = self.lines[self.pos].trim();
261→
262→            if bline == ".end" {
263→                self.pos += 1;
264→                return Ok(Proc {
265→                    name,
266→                    nlocals,
267→                    body,
268→                });
269→            }
270→
271→            if bline.is_empty() {
272→                body.push(Statement::Blank);
273→                self.pos += 1;
274→                continue;
275→            }
276→
277→            if bline.starts_with(';') {
278→                body.push(Statement::Comment(bline.to_string()));
279→                self.pos += 1;
280→                continue;
281→            }
282→
283→            // Label: ends with ':'
284→            if let Some(label) = bline.strip_suffix(':')
285→                && !label.contains(' ') && !label.contains('\t')
286→            {
287→                body.push(Statement::Label(label.to_string()));
288→                self.pos += 1;
289→                continue;
290→            }
291→
292→            // Instruction
293→            body.push(Statement::Instruction(self.parse_instruction(bline)?));
294→            self.pos += 1;
295→        }
296→
297→        Err(ParseError {
298→            line: line_num,
299→            message: format!(".proc {name} missing .end"),
300→        })
301→    }
302→
303→    fn parse_instruction(&self, line: &str) -> Result<Instruction, ParseError> {
304→        // Split off inline comment
305→        let (code, comment) = if let Some(idx) = line.find(';') {
306→            let (c, rest) = line.split_at(idx);
307→            (c.trim(), Some(rest.to_string()))
308→        } else {
309→            (line.trim(), None)
310→        };
311→
312→        let parts: Vec<&str> = code.splitn(2, char::is_whitespace).collect();
313→        let mnemonic = parts[0].to_string();
314→        let operand = parts.get(1).map(|s| s.trim().to_string()).filter(|s| !s.is_empty());
315→
316→        Ok(Instruction {
317→            mnemonic,
318→            operand,
319→            comment,
320→        })
321→    }
322→
323→    fn parse_global(&self) -> Result<Global, ParseError> {
324→        let line_num = self.pos + 1;
325→        let line = self.lines[self.pos].trim();
326→
327→        let rest = line.strip_prefix(".global").unwrap().trim();
328→        let rest = rest.split(';').next().unwrap().trim();
329→        let parts: Vec<&str> = rest.split_whitespace().collect();
330→
331→        if parts.len() < 2 {
332→            return Err(ParseError {
333→                line: line_num,
334→                message: ".global requires NAME and nwords".to_string(),
335→            });
336→        }
337→
338→        let name = parts[0].to_string();
339→        let nwords: u32 = parts[1].parse().map_err(|_| ParseError {
340→            line: line_num,
341→            message: format!("invalid nwords: {}", parts[1]),
342→        })?;
343→
344→        Ok(Global { name, nwords })
345→    }
346→
347→    fn parse_data(&self) -> Result<Data, ParseError> {
348→        let line_num = self.pos + 1;
349→        let line = self.lines[self.pos].trim();
350→
351→        let rest = line.strip_prefix(".data").unwrap().trim();
352→        let rest = rest.split(';').next().unwrap().trim();
353→        let parts: Vec<&str> = rest.splitn(2, char::is_whitespace).collect();
354→
355→        if parts.len() < 2 {
356→            return Err(ParseError {
357→                line: line_num,
358→                message: ".data requires NAME and byte values".to_string(),
359→            });
360→        }
361→
362→        let name = parts[0].to_string();
363→        let bytes: Result<Vec<u8>, _> = parts[1]
364→            .split(',')
365→            .map(|b| {
366→                b.trim().parse::<u8>().map_err(|_| ParseError {
367→                    line: line_num,
368→                    message: format!("invalid byte value: {}", b.trim()),
369→                })
370→            })
371→            .collect();
372→
373→        Ok(Data {
374→            name,
375→            bytes: bytes?,
376→        })
377→    }
378→
379→    fn parse_const(&self) -> Result<Const, ParseError> {
380→        let line_num = self.pos + 1;
381→        let line = self.lines[self.pos].trim();
382→
383→        let rest = line.strip_prefix(".const").unwrap().trim();
384→        let rest = rest.split(';').next().unwrap().trim();
385→        let parts: Vec<&str> = rest.splitn(2, char::is_whitespace).collect();
386→
387→        if parts.len() < 2 {
388→            return Err(ParseError {
389→                line: line_num,
390→                message: ".const requires NAME and value".to_string(),
391→            });
392→        }
393→
394→        Ok(Const {
395→            name: parts[0].to_string(),
396→            value: parts[1].trim().to_string(),
397→        })
398→    }
399→}
400→
401→/// Derive module name from filename: strip path and extension.
402→fn module_name_from_filename(filename: &str) -> String {
403→    let base = filename.rsplit('/').next().unwrap_or(filename);
404→    base.strip_suffix(".spc").unwrap_or(base).to_string()
405→}
