433→    #[test]
434→    fn test_parse_data() {
435→        let src = ".data msg 72, 101, 108, 108, 111, 10, 0\n";
436→        let m = parse(src, "test.spc").unwrap();
437→        assert_eq!(m.items.len(), 1);
438→        match &m.items[0] {
439→            Item::Data(d) => {
440→                assert_eq!(d.name, "msg");
441→                assert_eq!(d.bytes, vec![72, 101, 108, 108, 111, 10, 0]);
442→            }
443→            _ => panic!("expected Data"),
444→        }
445→    }
