447→    #[test]
448→    fn test_parse_const() {
449→        let src = ".const MAX 255\n";
450→        let m = parse(src, "test.spc").unwrap();
451→        assert_eq!(m.items.len(), 1);
452→        assert_eq!(
453→            m.items[0],
454→            Item::Const(Const {
455→                name: "MAX".to_string(),
456→                value: "255".to_string()
457→            })
458→        );
459→    }
