461→    #[test]
462→    fn test_parse_simple_proc() {
463→        let src = "\
464→.proc main 0
465→    push 42
466→    halt
467→.end
468→";
469→        let m = parse(src, "test.spc").unwrap();
470→        assert_eq!(m.items.len(), 1);
471→        match &m.items[0] {
472→            Item::Proc(p) => {
473→                assert_eq!(p.name, "main");
474→                assert_eq!(p.nlocals, 0);
475→                assert_eq!(p.body.len(), 2);
476→                assert_eq!(
477→                    p.body[0],
478→                    Statement::Instruction(Instruction {
479→                        mnemonic: "push".to_string(),
480→                        operand: Some("42".to_string()),
481→                        comment: None,
482→                    })
483→                );
484→                assert_eq!(
485→                    p.body[1],
486→                    Statement::Instruction(Instruction {
487→                        mnemonic: "halt".to_string(),
488→                        operand: None,
489→                        comment: None,
490→                    })
491→                );
492→            }
493→            _ => panic!("expected Proc"),
494→        }
495→    }
