691→    #[test]
692→    fn test_parse_runtime_spc() {
693→        let src = "\
694→; pr24p — Pascal Runtime Library
695→; Phase 0: Hand-written .spc stubs
696→
697→.proc _p24p_write_int 1
698→    enter 1
699→    loada 0
700→    dup
701→    push 0
702→    lt
703→    jz positive
704→    push 45
705→    sys 1
706→    neg
707→positive:
708→    storel 0
709→    push 0
710→extract:
711→    loadl 0
712→    push 10
713→    mod
714→    push 48
715→    add
716→    loadl 0
717→    push 10
